/**
 * Defines the possible abi call signatures.
 */
export type ProtocolConfigSignatures = keyof ProtocolConfigTypes['methods']
/**
 * Defines an object containing all relevant parameters for a single call to the contract.
 */
export type CallParams<TArgs> = Expand<
  Omit<AppClientMethodCallParams, 'method' | 'args' | 'onComplete'> &
    {
      /** The args for the ABI method call, either as an ordered array or an object */
      args: Expand<TArgs>
    }
>
/**
 * Maps a method signature from the ProtocolConfig smart contract to the method's arguments in either tuple or struct form
 */
export type MethodArgs<TSignature extends ProtocolConfigSignatures> = ProtocolConfigTypes['methods'][TSignature]['argsObj' | 'argsTuple']
/**
 * Maps a method signature from the ProtocolConfig smart contract to the method's return type
 */
export type MethodReturn<TSignature extends ProtocolConfigSignatures> = ProtocolConfigTypes['methods'][TSignature]['returns']

/**
 * Defines the shape of the keyed global state of the application.
 */
export type GlobalKeysState = ProtocolConfigTypes['state']['global']['keys']



